/**
 * Public Landing Page
 * Showcases the Safety Manager platform to new visitors
 */

import React from 'react';
import { useNavigate } from 'react-router-dom';
import { Shield, CheckCircle, Users, FileText, Lock, Zap, BarChart3, Globe } from 'lucide-react';

const LandingPage = () => {
  const navigate = useNavigate();

  const features = [
    {
      icon: FileText,
      title: 'Digital Forms',
      description: 'Comprehensive safety documentation with JSA, LOTO, injury reports, accident reports, spill reports, and monthly inspections.'
    },
    {
      icon: Lock,
      title: 'Secure & Compliant',
      description: 'Enterprise-grade security with JWT authentication, encrypted data transmission, and comprehensive audit trails.'
    },
    {
      icon: Users,
      title: 'Multi-User Collaboration',
      description: 'Role-based access control, team coordination, and real-time form submission tracking.'
    },
    {
      icon: Zap,
      title: 'Real-Time Alerts',
      description: 'Instant notifications for critical incidents, safety violations, and inspection findings.'
    },
    {
      icon: BarChart3,
      title: 'Analytics Dashboard',
      description: 'Visual reporting with safety metrics, trend analysis, and incident heat maps.'
    },
    {
      icon: Globe,
      title: 'Photo Evidence',
      description: 'Integrated camera functionality for capturing evidence with automatic field linking and PDF embedding.'
    }
  ];

  const benefits = [
    { number: '6', label: 'Safety Forms', icon: '📋' },
    { number: '100%', label: 'Digital Compliant', icon: '✓' },
    { number: '24/7', label: 'Accessible', icon: '🔐' },
    { number: '2m', label: 'Form Completion', icon: '⚡' }
  ];

  return (
    <div className="min-h-screen bg-white">
      {/* Navigation */}
      <nav className="bg-white border-b border-gray-100 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-6 py-4 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-blue-600 p-2 rounded-lg">
              <Shield size={24} className="text-white" />
            </div>
            <h1 className="text-2xl font-bold text-gray-900">Safety Manager</h1>
          </div>
          <button
            onClick={() => navigate('/login')}
            className="px-6 py-2 bg-blue-600 hover:bg-blue-700 text-white font-semibold rounded-lg transition"
          >
            Sign In
          </button>
        </div>
      </nav>

      {/* Hero Section */}
      <section className="relative overflow-hidden bg-gradient-to-br from-blue-50 to-indigo-50 py-20 md:py-32">
        <div className="absolute top-0 right-0 -z-10 w-96 h-96 bg-blue-200 rounded-full mix-blend-multiply filter blur-3xl opacity-20"></div>
        <div className="absolute bottom-0 left-0 -z-10 w-96 h-96 bg-purple-200 rounded-full mix-blend-multiply filter blur-3xl opacity-20"></div>

        <div className="max-w-7xl mx-auto px-6">
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 items-center">
            <div>
              <div className="inline-block bg-blue-100 text-blue-700 px-4 py-2 rounded-full text-sm font-semibold mb-6">
                Safety Management Platform
              </div>
              <h1 className="text-5xl md:text-6xl font-bold text-gray-900 mb-6 leading-tight">
                Professional Safety Documentation Made Simple
              </h1>
              <p className="text-xl text-gray-600 mb-8 leading-relaxed">
                Streamline incident reporting, inspections, and compliance tracking for modern seafood processing facilities with our comprehensive digital safety platform.
              </p>

              <div className="flex flex-col sm:flex-row gap-4">
                <button
                  onClick={() => navigate('/login')}
                  className="px-8 py-4 bg-gradient-to-r from-blue-600 to-blue-700 hover:from-blue-700 hover:to-blue-800 text-white font-semibold rounded-lg transition shadow-lg hover:shadow-xl"
                >
                  Get Started
                </button>
                <button
                  className="px-8 py-4 border-2 border-gray-300 text-gray-900 font-semibold rounded-lg transition hover:bg-gray-50"
                >
                  Learn More
                </button>
              </div>

              <div className="mt-12 flex items-center gap-8 pt-8 border-t border-gray-200">
                <div>
                  <p className="text-3xl font-bold text-gray-900">6</p>
                  <p className="text-gray-600 text-sm">Safety Forms</p>
                </div>
                <div>
                  <p className="text-3xl font-bold text-gray-900">45+</p>
                  <p className="text-gray-600 text-sm">Form Fields</p>
                </div>
                <div>
                  <p className="text-3xl font-bold text-gray-900">100%</p>
                  <p className="text-gray-600 text-sm">Digital</p>
                </div>
              </div>
            </div>

            <div className="relative">
              <div className="bg-gradient-to-br from-blue-600 to-blue-800 rounded-2xl p-8 shadow-2xl">
                <div className="bg-white rounded-lg p-6 space-y-4">
                  <div className="h-3 bg-gray-200 rounded-full w-2/3"></div>
                  <div className="h-3 bg-gray-200 rounded-full w-full"></div>
                  <div className="h-3 bg-gray-200 rounded-full w-5/6"></div>

                  <div className="pt-6 space-y-2">
                    <div className="flex gap-2">
                      <div className="h-8 w-8 bg-blue-100 rounded-lg"></div>
                      <div className="h-8 w-8 bg-red-100 rounded-lg"></div>
                      <div className="h-8 w-8 bg-green-100 rounded-lg"></div>
                    </div>
                    <div className="h-2 bg-gray-100 rounded-full"></div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* Benefits Section */}
      <section className="py-16 md:py-24 bg-white">
        <div className="max-w-7xl mx-auto px-6">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
            {benefits.map((benefit, index) => (
              <div key={index} className="text-center p-6 bg-gradient-to-br from-blue-50 to-indigo-50 rounded-xl">
                <p className="text-4xl mb-2">{benefit.icon}</p>
                <p className="text-4xl font-bold text-gray-900">{benefit.number}</p>
                <p className="text-gray-600 text-sm mt-2">{benefit.label}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Features Section */}
      <section className="py-16 md:py-24 bg-gray-50">
        <div className="max-w-7xl mx-auto px-6">
          <div className="text-center mb-16">
            <h2 className="text-4xl md:text-5xl font-bold text-gray-900 mb-6">Powerful Features</h2>
            <p className="text-xl text-gray-600 max-w-2xl mx-auto">Everything you need to manage safety documentation efficiently and professionally</p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {features.map((feature, index) => {
              const Icon = feature.icon;
              return (
                <div key={index} className="bg-white rounded-xl p-8 shadow-sm hover:shadow-lg transition">
                  <div className="bg-blue-100 w-12 h-12 rounded-lg flex items-center justify-center mb-4">
                    <Icon size={24} className="text-blue-600" />
                  </div>
                  <h3 className="text-xl font-semibold text-gray-900 mb-3">{feature.title}</h3>
                  <p className="text-gray-600 leading-relaxed">{feature.description}</p>
                </div>
              );
            })}
          </div>
        </div>
      </section>

      {/* Security Section */}
      <section className="py-16 md:py-24 bg-gradient-to-br from-blue-600 to-blue-800 text-white">
        <div className="max-w-7xl mx-auto px-6">
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 items-center">
            <div>
              <h2 className="text-4xl md:text-5xl font-bold mb-6">Enterprise-Grade Security</h2>
              <p className="text-blue-100 text-lg mb-8 leading-relaxed">
                Your safety data is protected with current industry standards including JWT authentication, encrypted transmission, and comprehensive audit trails.
              </p>

              <div className="space-y-4">
                <div className="flex items-center gap-3">
                  <CheckCircle size={24} className="text-green-300 flex-shrink-0" />
                  <span className="text-blue-100">End-to-end encryption</span>
                </div>
                <div className="flex items-center gap-3">
                  <CheckCircle size={24} className="text-green-300 flex-shrink-0" />
                  <span className="text-blue-100">JWT authentication</span>
                </div>
                <div className="flex items-center gap-3">
                  <CheckCircle size={24} className="text-green-300 flex-shrink-0" />
                  <span className="text-blue-100">Complete audit trails</span>
                </div>
                <div className="flex items-center gap-3">
                  <CheckCircle size={24} className="text-green-300 flex-shrink-0" />
                  <span className="text-blue-100">Role-based access control</span>
                </div>
              </div>
            </div>

            <div className="bg-white/10 backdrop-blur-sm rounded-2xl p-8 border border-white/20">
              <div className="space-y-6">
                <div>
                  <div className="flex items-center gap-2 mb-2">
                    <Lock size={20} className="text-green-300" />
                    <h4 className="font-semibold">Data Protection</h4>
                  </div>
                  <p className="text-blue-100 text-sm">All data encrypted with industry-standard algorithms</p>
                </div>
                <div>
                  <div className="flex items-center gap-2 mb-2">
                    <Shield size={20} className="text-green-300" />
                    <h4 className="font-semibold">Compliance Ready</h4>
                  </div>
                  <p className="text-blue-100 text-sm">Meets OSHA documentation requirements</p>
                </div>
                <div>
                  <div className="flex items-center gap-2 mb-2">
                    <Users size={20} className="text-green-300" />
                    <h4 className="font-semibold">User Management</h4>
                  </div>
                  <p className="text-blue-100 text-sm">Fine-grained permission control</p>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* CTA Section */}
      <section className="py-16 md:py-24 bg-white">
        <div className="max-w-3xl mx-auto px-6 text-center">
          <h2 className="text-4xl md:text-5xl font-bold text-gray-900 mb-6">Ready to Improve Your Safety Management?</h2>
          <p className="text-xl text-gray-600 mb-10">Start documenting safety incidents and inspections professionally today</p>

          <button
            onClick={() => navigate('/login')}
            className="px-8 py-4 bg-gradient-to-r from-blue-600 to-blue-700 hover:from-blue-700 hover:to-blue-800 text-white font-semibold rounded-lg transition shadow-lg hover:shadow-xl text-lg"
          >
            Sign In to Safety Manager
          </button>

          <p className="text-gray-500 text-sm mt-6">
            Demo credentials provided on login page • No credit card required
          </p>
        </div>
      </section>

      {/* Footer */}
      <footer className="bg-gray-900 text-gray-300 py-12 border-t border-gray-800">
        <div className="max-w-7xl mx-auto px-6">
          <div className="grid grid-cols-1 md:grid-cols-4 gap-8 mb-12">
            <div>
              <div className="flex items-center gap-2 mb-4">
                <Shield size={24} className="text-blue-400" />
                <h3 className="font-bold text-white">Safety Manager</h3>
              </div>
              <p className="text-sm text-gray-400">Professional safety documentation for modern facilities</p>
            </div>

            <div>
              <h4 className="font-semibold text-white mb-4">Product</h4>
              <ul className="space-y-2 text-sm">
                <li><a href="#" className="hover:text-white transition">Features</a></li>
                <li><a href="#" className="hover:text-white transition">Pricing</a></li>
                <li><a href="#" className="hover:text-white transition">Security</a></li>
              </ul>
            </div>

            <div>
              <h4 className="font-semibold text-white mb-4">Company</h4>
              <ul className="space-y-2 text-sm">
                <li><a href="#" className="hover:text-white transition">About</a></li>
                <li><a href="#" className="hover:text-white transition">Contact</a></li>
                <li><a href="#" className="hover:text-white transition">Careers</a></li>
              </ul>
            </div>

            <div>
              <h4 className="font-semibold text-white mb-4">Legal</h4>
              <ul className="space-y-2 text-sm">
                <li><a href="#" className="hover:text-white transition">Privacy</a></li>
                <li><a href="#" className="hover:text-white transition">Terms</a></li>
                <li><a href="#" className="hover:text-white transition">Compliance</a></li>
              </ul>
            </div>
          </div>

          <div className="border-t border-gray-800 pt-8 flex flex-col md:flex-row items-center justify-between">
            <p className="text-sm">© 2026 Safety Manager by Silver Bay Seafoods. All rights reserved.</p>
            <div className="flex gap-6 mt-6 md:mt-0">
              <a href="#" className="text-gray-400 hover:text-white transition">Twitter</a>
              <a href="#" className="text-gray-400 hover:text-white transition">LinkedIn</a>
              <a href="#" className="text-gray-400 hover:text-white transition">Email</a>
            </div>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default LandingPage;
